// Generate the last 60-minute time window in ISO8601
const now   = new Date();
const start = new Date(now.getTime() - 60 * 60 * 1000);
return [{
  json: {
    endTime:   now.toISOString(),
    startTime: start.toISOString(),
    endEpoch:  Math.floor(now.getTime() / 1000),
    startEpoch: Math.floor(start.getTime() / 1000)
  }
}];

// Analyse all metrics and detect performance issues
const CPU_THRESHOLD_WARN  = parseInt($env.CPU_WARN_THRESHOLD  || '70');
const CPU_THRESHOLD_CRIT  = parseInt($env.CPU_CRIT_THRESHOLD  || '90');
const MEM_THRESHOLD_WARN  = parseInt($env.MEM_WARN_THRESHOLD  || '75');
const MEM_THRESHOLD_CRIT  = parseInt($env.MEM_CRIT_THRESHOLD  || '95');

// Parse AWS CloudWatch responses (simplified)
const awsCpuRaw = $('AWS: Get EC2 CPU via CloudWatch').first().json;
const awsMemRaw = $('AWS: Get EC2 Memory via CloudWatch').first().json;
const azCpuRaw  = $('Azure: Get VM CPU Metrics').first().json;
const azMemRaw  = $('Azure: Get VM Memory Metrics').first().json;

// Normalise to a common schema
function parseAwsMetrics(raw, metricName) {
  const results = raw?.MetricDataResults || raw?.Datapoints || [];
  if (!results.length) return [{ instance: 'aws-demo-node', metric: metricName, value: 0, unit: '%', source: 'AWS CloudWatch' }];
  return results.map((r, i) => ({
    instance: r.Label || `aws-instance-${i}`,
    metric:   metricName,
    value:    r.Values?.[0] ?? r.Average ?? 0,
    unit:     '%',
    source:   'AWS CloudWatch'
  }));
}

function parseAzureMetrics(raw, metricName) {
  const values = raw?.value || [];
  if (!values.length) return [{ instance: 'azure-demo-node', metric: metricName, value: 0, unit: '%', source: 'Azure Monitor' }];
  return values.map(v => ({
    instance: v.name?.localizedValue || v.id || 'azure-vm',
    metric:   metricName,
    value:    v.timeseries?.[0]?.data?.slice(-1)?.[0]?.average ?? 0,
    unit:     metricName === 'Memory' ? 'bytes' : '%',
    source:   'Azure Monitor'
  }));
}

const metrics = [
  ...parseAwsMetrics(awsCpuRaw, 'CPU'),
  ...parseAwsMetrics(awsMemRaw, 'Memory'),
  ...parseAzureMetrics(azCpuRaw, 'CPU'),
  ...parseAzureMetrics(azMemRaw, 'Memory')
];

const issues = metrics.filter(m => {
  if (m.metric === 'CPU')    return m.value >= CPU_THRESHOLD_WARN;
  if (m.metric === 'Memory') return m.value >= MEM_THRESHOLD_WARN;
  return false;
}).map(m => ({
  ...m,
  severity: (() => {
    if (m.metric === 'CPU')    return m.value >= CPU_THRESHOLD_CRIT  ? '🔴 CRITICAL' : '🟡 WARNING';
    if (m.metric === 'Memory') return m.value >= MEM_THRESHOLD_CRIT  ? '🔴 CRITICAL' : '🟡 WARNING';
    return '⚪ INFO';
  })()
}));

const hasCritical = issues.some(i => i.severity.includes('CRITICAL'));
const now = new Date().toUTCString();

// Build rows
const allRows = metrics.map(m => {
  let badge = '🟢';
  if (m.metric === 'CPU'    && m.value >= CPU_THRESHOLD_CRIT) badge = '🔴';
  else if (m.metric === 'CPU'    && m.value >= CPU_THRESHOLD_WARN) badge = '🟡';
  else if (m.metric === 'Memory' && m.value >= MEM_THRESHOLD_CRIT) badge = '🔴';
  else if (m.metric === 'Memory' && m.value >= MEM_THRESHOLD_WARN) badge = '🟡';
  return `<tr><td>${m.source}</td><td>${m.instance}</td><td>${m.metric}</td><td>${badge} ${m.value.toFixed ? m.value.toFixed(2) : m.value}${m.unit}</td></tr>`;
}).join('');

const issueRows = issues.length
  ? issues.map(i => `<tr style='background:#fff3cd'><td>${i.source}</td><td>${i.instance}</td><td>${i.metric}</td><td>${i.severity}</td><td>${i.value.toFixed ? i.value.toFixed(2) : i.value}${i.unit}</td></tr>`).join('')
  : `<tr><td colspan='5' style='color:green'>✅ No performance issues detected</td></tr>`;

const status = hasCritical ? '🔴 CRITICAL PERFORMANCE ISSUE' : issues.length ? '🟡 PERFORMANCE WARNING' : '🟢 ALL NODES HEALTHY';

const html = `<!DOCTYPE html><html><head><style>
body{font-family:Arial,sans-serif;padding:24px;color:#222}
h1{color:#1a1a2e}h2{color:#16213e;margin-top:30px}
table{border-collapse:collapse;width:100%;margin-top:10px}
th{background:#16213e;color:white;padding:8px 12px;text-align:left}
td{border:1px solid #ddd;padding:8px 12px}
tr:nth-child(even){background:#f4f4f4}
</style></head><body>
<h1>☁️ Cloud Node Utilization Report</h1>
<p><strong>Generated:</strong> ${now}</p>
<p><strong>Period:</strong> Last 60 minutes</p>
<p><strong>Overall Status:</strong> ${status}</p>
<p><strong>Thresholds:</strong> CPU Warn=${CPU_THRESHOLD_WARN}% Crit=${CPU_THRESHOLD_CRIT}% | Mem Warn=${MEM_THRESHOLD_WARN}% Crit=${MEM_THRESHOLD_CRIT}%</p>
<h2>🚨 Performance Issues (${issues.length})</h2>
<table><tr><th>Source</th><th>Instance</th><th>Metric</th><th>Severity</th><th>Value</th></tr>${issueRows}</table>
<h2>📊 All Metrics (${metrics.length} data points)</h2>
<table><tr><th>Source</th><th>Instance</th><th>Metric</th><th>Value</th></tr>${allRows}</table>
<hr/><p style='font-size:12px;color:#666'>Auto-generated by n8n Cloud Monitoring Workflow</p>
</body></html>`;

return [{ json: { html, subject: `[Cloud Monitor] ${status} — ${now}`, issues: issues.length, hasCritical, status } }];
